public class ExtractField<T>
  public static T GetField(string input, int n, char delimiter)
  {
    string[] fields = input.Split(delimiter);
    return fields[n];
  }
}

// Usage
string input = "123abc";
int n = 3;
char delimiter = ' ';
string firstName = ExtractField<string>(input, n, delimiter);
Console.WriteLine(firstName); // Output: abc

public class ExtractField<T>
  public static readonly T GetField(ReadOnlySpan<char> input, int n, char delimiter)
  {
    ReadOnlySpan<char> temp = new char[input.Length];
    for (int i = 0; i < input.Length; i++)
    {
      if (i + n < input.Length && input[i + n] == delimiter)
        return temp.Slice(i, n - i + 1);
    }
    return default;
  }
}
